func (this *PhemexCore) ParseSafeNumber(optionalArgs ...any) any {
	value := GetArg(optionalArgs, 0, nil)
	_ = value
	if IsTrue(IsEqual(value, nil)) {
		return value
	}
	var parts any = Split(value, ",")
	value = Join(parts, "")
	parts = Split(value, " ")
	return this.SafeNumber(parts, 0)
}
