		//                     "majorSymbol":true,
		//                     "defaultLeverage":"-10",
		//                     "fundingInterval":28800,
		//                     "maxLeverage":100
		//                 },
		//                 {
		//                     "symbol":"sBTCUSDT",
		//                     "code":1001,
		//                     "type":"Spot",
		//                     "displaySymbol":"BTC / USDT",
		//                     "quoteCurrency":"USDT",
		//                     "priceScale":8,
		//                     "ratioScale":8,
		//                     "pricePrecision":2,
		//                     "baseCurrency":"BTC",
		//                     "baseTickSize":"0.000001 BTC",
		//                     "baseTickSizeEv":100,
