func (this *PhemexCore) ParseFundingRate(contract any, optionalArgs ...any) any {
	//
	//     {
	//         "askEp": 2332500,
	//         "bidEp": 2331000,
	//         "fundingRateEr": 10000,
	//         "highEp": 2380000,
	//         "indexEp": 2329057,
	//         "lastEp": 2331500,
	//         "lowEp": 2274000,
	//         "markEp": 2329232,
	//         "openEp": 2337500,
	//         "openInterest": 1298050,
	//         "predFundingRateEr": 19921,
	//         "symbol": "ETHUSD",
	//         "timestamp": 1592474241582701416,
	//         "turnoverEv": 47228362330,
	//         "volume": 4053863
	//     }
	//
	// linear swap v2
	//
	//     {
	//         "closeRp":"16820.5",
	//         "fundingRateRr":"0.0001",
	//         "highRp":"16962.1",
	//         "indexPriceRp":"16830.15651565",
	//         "lowRp":"16785",
	//         "markPriceRp":"16830.97534951",
	//         "openInterestRv":"1323.596",
	//         "openRp":"16851.7",
	//         "predFundingRateRr":"0.0001",
	//         "symbol":"BTCUSDT",
	//         "timestamp":"1672142789065593096",
	//         "turnoverRv":"124835296.0538",
	//         "volumeRq":"7406.95"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId any = this.SafeString(contract, "symbol")
	var symbol any = this.SafeSymbol(marketId, market)
	var timestamp any = this.SafeIntegerProduct(contract, "timestamp", 0.000001)
	var markEp any = this.FromEp(this.SafeString(contract, "markEp"), market)
	var indexEp any = this.FromEp(this.SafeString(contract, "indexEp"), market)
	var fundingRateEr any = this.FromEr(this.SafeString(contract, "fundingRateEr"), market)
	var nextFundingRateEr any = this.FromEr(this.SafeString(contract, "predFundingRateEr"), market)
	return map[string]any{
		"info":                     contract,
		"symbol":                   symbol,
		"markPrice":                this.SafeNumber(contract, "markPriceRp", markEp),
		"indexPrice":               this.SafeNumber(contract, "indexPriceRp", indexEp),
		"interestRate":             nil,
		"estimatedSettlePrice":     nil,
		"timestamp":                timestamp,
		"datetime":                 this.Iso8601(timestamp),
		"fundingRate":              this.SafeNumber(contract, "fundingRateRr", fundingRateEr),
		"fundingTimestamp":         nil,
		"fundingDatetime":          nil,
		"nextFundingRate":          this.SafeNumber(contract, "predFundingRateRr", nextFundingRateEr),
		"nextFundingTimestamp":     nil,
		"nextFundingDatetime":      nil,
		"previousFundingRate":      nil,
		"previousFundingTimestamp": nil,
		"previousFundingDatetime":  nil,
		"interval":                 nil,
	}
}

